package main

import (
    "fmt"
    "sync"
    "time"
)

// ---- Worker pool pattern ----
func worker(id int, jobs <-chan int, results chan<- int, wg *sync.WaitGroup) {
    defer wg.Done()
    for job := range jobs {
        fmt.Printf("Worker %d processing job %d\n", id, job)
        time.Sleep(100 * time.Millisecond)  // Simulate work
        results <- job * 2
    }
}

func main() {
    // ---- Basic worker pool ----
    fmt.Println("=== Worker Pool ===")

    const numJobs = 10
    const numWorkers = 3

    jobs := make(chan int, numJobs)
    results := make(chan int, numJobs)
    var wg sync.WaitGroup

    // ---- Start workers ----
    for i := 1; i <= numWorkers; i++ {
        wg.Add(1)
        go worker(i, jobs, results, &wg)
    }

    // ---- Send jobs ----
    for j := 1; j <= numJobs; j++ {
        jobs <- j
    }
    close(jobs)

    // ---- Wait for workers to finish ----
    go func() {
        wg.Wait()
        close(results)
    }()

    // ---- Collect results ----
    for result := range results {
        fmt.Printf("Result: %d\n", result)
    }

    // ---- Worker pool with different work ----
    fmt.Println("\n=== Worker Pool with Different Work ===")

    type Work struct {
        ID    int
        Value int
    }

    workJobs := make(chan Work, 5)
    workResults := make(chan int, 5)

    // ---- Worker function for different work ----
    workWorker := func(id int, jobs <-chan Work, results chan<- int) {
        for job := range jobs {
            fmt.Printf("Worker %d: processing work %d (value: %d)\n", id, job.ID, job.Value)
            time.Sleep(50 * time.Millisecond)
            results <- job.Value * job.Value
        }
    }

    var wg2 sync.WaitGroup

    for i := 1; i <= 2; i++ {
        wg2.Add(1)
        go func(id int) {
            defer wg2.Done()
            workWorker(id, workJobs, workResults)
        }(i)
    }

    for i := 1; i <= 5; i++ {
        workJobs <- Work{ID: i, Value: i * 10}
    }
    close(workJobs)

    go func() {
        wg2.Wait()
        close(workResults)
    }()

    for result := range workResults {
        fmt.Printf("Work result: %d\n", result)
    }
}

